from flask import Flask, session, redirect, url_for, request, render_template_string

app = Flask(__name__)
app.secret_key = "change-this-secret-key"

USERS = {
    "admin": "password123",
    "user": "secret",
}

LOGIN_TEMPLATE = """
<!doctype html>
<title>Login</title>
<h2>Login</h2>
{% if error %}
<p style="color:red;">{{ error }}</p>
{% endif %}
<form method="post">
  <p><input type="text" name="username" placeholder="Username"></p>
  <p><input type="password" name="password" placeholder="Password"></p>
  <p><button type="submit">Log In</button></p>
</form>
"""

HOME_TEMPLATE = """
<!doctype html>
<title>Home</title>
{% if username %}
  <h2>Welcome, {{ username }}</h2>
  <p>You are logged in.</p>
  <p><a href="{{ url_for('dashboard') }}">Go to Dashboard</a></p>
  <p><a href="{{ url_for('logout') }}">Log Out</a></p>
{% else %}
  <h2>Welcome, Guest</h2>
  <p><a href="{{ url_for('login') }}">Log In</a></p>
{% endif %}
"""

DASHBOARD_TEMPLATE = """
<!doctype html>
<title>Dashboard</title>
<h2>Dashboard</h2>
<p>Hello, {{ username }}. This is a protected page.</p>
<p><a href="{{ url_for('home') }}">Home</a></p>
<p><a href="{{ url_for('logout') }}">Log Out</a></p>
"""

def is_logged_in():
    return 'user' in session

def current_user():
    return session.get('user')

def login_user(username):
    session['user'] = username
    session.permanent = True

def logout_user():
    session.pop('user', None)

@app.route('/')
def home():
    return render_template_string(HOME_TEMPLATE, username=current_user())

@app.route('/login', methods=['GET', 'POST'])
def login():
    if is_logged_in():
        return redirect(url_for('dashboard'))

    error = None
    if request.method == 'POST':
        username = request.form.get('username', '')
        password = request.form.get('password', '')

        if username in USERS and USERS[username] == password:
            login_user(username)
            return redirect(url_for('dashboard'))
        else:
            error = 'Invalid username or password'

    return render_template_string(LOGIN_TEMPLATE, error=error)

@app.route('/dashboard')
def dashboard():
    if not is_logged_in():
        return redirect(url_for('login'))
    return render_template_string(DASHBOARD_TEMPLATE, username=current_user())

@app.route('/logout')
def logout():
    logout_user()
    return redirect(url_for('home'))

if __name__ == '__main__':
    app.run(debug=True)